import Home from "./pages/Home"
import {BrowserRouter, Routes, Route} from "react-router-dom"
// import axios from "axios"


class App extends React.Component {
    render() {
        return (<div>
            <BrowserRouter>

            </BrowserRouter>
            <Routes>
                <Route path='/' element={<Home />}></Route>
            </Routes>
        </div>)
    }
}



export default App
